Be very careful with error messages in APIs - verbose errors are a goldmine for attackers. They reveal your internal architecture, database schema, file paths, and technology stack.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const mysql = require('mysql2/promise');

const app = express();
app.use(express.json());

const pool = mysql.createPool({
  host: 'db.internal.company.com',
  user: 'app_user',
  password: 'SuperSecret123!',
  database: 'customers_prod'
});

app.get('/api/users/:id', async (req, res) => {
  try {
    const [rows] = await pool.execute(
      'SELECT * FROM users WHERE id = ?',
      [req.params.id]
    );
    if (rows.length === 0) {
      return res.status(404).json({
        error: 'User not found in table users (database: customers_prod)'
      });
    }
    res.json(rows[0]);
  } catch (error) {
    // DANGEROUS: Exposing full error details
    res.status(500).json({
      error: error.message,
      stack: error.stack,
      query: error.sql,
      code: error.code,
      errno: error.errno,
      sqlState: error.sqlState
    });
  }
});

// Global error handler - also vulnerable
app.use((err, req, res, next) => {
  res.status(500).json({
    message: err.message,
    stack: err.stack,
    file: err.fileName,
    line: err.lineNumber
  });
});

app.listen(3000);
```

**Example Verbose Error Response**:
```json
{
  "error": "ER_BAD_FIELD_ERROR: Unknown column 'password_hash' in 'field list'",
  "stack": "Error: ER_BAD_FIELD_ERROR\n    at /var/www/app/node_modules/mysql2/lib/packets/packet.js:728:17\n    at /var/www/app/src/controllers/UserController.js:45:23",
  "query": "SELECT id, username, password_hash, email, ssn FROM users WHERE id = 1",
  "code": "ER_BAD_FIELD_ERROR",
  "errno": 1054,
  "sqlState": "42S22"
}
```

**Why This Is Dangerous**:
- Reveals internal database schema (table names, column names like `password_hash`, `ssn`)
- Exposes file system paths (`/var/www/app/src/controllers/`)
- Shows SQL queries that can be analyzed for injection points
- Discloses technology stack versions through stack traces
- Helps attackers map internal network (`db.internal.company.com`)

**SECURE VERSION**:

```javascript
const express = require('express');
const mysql = require('mysql2/promise');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Configuration from environment variables
const pool = mysql.createPool({
  host: process.env.DB_HOST,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  database: process.env.DB_NAME
});

// Error ID generator for correlation
function generateErrorId() {
  return crypto.randomBytes(8).toString('hex');
}

// Centralized error logger (server-side only)
function logError(errorId, error, req) {
  console.error(JSON.stringify({
    timestamp: new Date().toISOString(),
    errorId: errorId,
    message: error.message,
    stack: error.stack,
    method: req.method,
    path: req.path,
    ip: req.ip,
    userAgent: req.get('User-Agent')
  }));
}

app.get('/api/users/:id', async (req, res) => {
  const errorId = generateErrorId();

  try {
    const userId = parseInt(req.params.id, 10);
    if (isNaN(userId) || userId <= 0) {
      return res.status(400).json({
        error: 'Invalid request',
        errorId: errorId
      });
    }

    const [rows] = await pool.execute(
      'SELECT id, username, email FROM users WHERE id = ?',
      [userId]
    );

    if (rows.length === 0) {
      return res.status(404).json({
        error: 'Resource not found',
        errorId: errorId
      });
    }

    res.json(rows[0]);
  } catch (error) {
    // Log full details server-side
    logError(errorId, error, req);

    // Return generic message to client
    res.status(500).json({
      error: 'An unexpected error occurred',
      errorId: errorId,
      support: 'Contact support with this error ID'
    });
  }
});

// Secure global error handler
app.use((err, req, res, next) => {
  const errorId = generateErrorId();
  logError(errorId, err, req);

  res.status(500).json({
    error: 'An unexpected error occurred',
    errorId: errorId
  });
});

app.listen(3000);
```

**Key Security Controls**:
- **Generic client messages**: Users see "An unexpected error occurred" not internal details
- **Error correlation IDs**: Random IDs link user reports to server logs without exposing internals
- **Server-side logging**: Full error details logged securely for debugging, never sent to clients
- **Environment variables**: Sensitive configuration kept out of code

Excellent question! Environment-aware error handling is crucial for production security. Here's a production-ready pattern that provides detailed errors in development while remaining secure in production.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json());

// Environment detection
const isDevelopment = process.env.NODE_ENV === 'development';
const isProduction = process.env.NODE_ENV === 'production';

// Production-grade logger with different transports
const logger = winston.createLogger({
  level: isDevelopment ? 'debug' : 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'user-api' },
  transports: [
    new winston.transports.File({ 
      filename: 'error.log', 
      level: 'error',
      maxsize: 10485760, // 10MB
      maxFiles: 5
    }),
    new winston.transports.File({ 
      filename: 'combined.log',
      maxsize: 10485760,
      maxFiles: 10
    })
  ]
});

// Console output only in development
if (isDevelopment) {
  logger.add(new winston.transports.Console({
    format: winston.format.combine(
      winston.format.colorize(),
      winston.format.simple()
    )
  }));
}

// Error classification for appropriate responses
const ErrorTypes = {
  VALIDATION: 'VALIDATION_ERROR',
  NOT_FOUND: 'NOT_FOUND',
  UNAUTHORIZED: 'UNAUTHORIZED',
  FORBIDDEN: 'FORBIDDEN',
  RATE_LIMITED: 'RATE_LIMITED',
  INTERNAL: 'INTERNAL_ERROR',
  DATABASE: 'DATABASE_ERROR',
  EXTERNAL_SERVICE: 'EXTERNAL_SERVICE_ERROR'
};

// Custom application error class
class AppError extends Error {
  constructor(message, type, statusCode, details = null) {
    super(message);
    this.type = type;
    this.statusCode = statusCode;
    this.details = details;
    this.isOperational = true;
    Error.captureStackTrace(this, this.constructor);
  }
}

// Generate secure correlation ID
function generateCorrelationId() {
  return `err_${Date.now()}_${crypto.randomBytes(6).toString('hex')}`;
}

// Sanitize error for client response
function sanitizeErrorForClient(error, correlationId) {
  // Safe messages that don't reveal internals
  const safeMessages = {
    [ErrorTypes.VALIDATION]: 'Invalid request data',
    [ErrorTypes.NOT_FOUND]: 'Resource not found',
    [ErrorTypes.UNAUTHORIZED]: 'Authentication required',
    [ErrorTypes.FORBIDDEN]: 'Access denied',
    [ErrorTypes.RATE_LIMITED]: 'Too many requests',
    [ErrorTypes.INTERNAL]: 'An unexpected error occurred',
    [ErrorTypes.DATABASE]: 'Service temporarily unavailable',
    [ErrorTypes.EXTERNAL_SERVICE]: 'Service temporarily unavailable'
  };

  const baseResponse = {
    success: false,
    error: {
      code: error.type || ErrorTypes.INTERNAL,
      message: safeMessages[error.type] || safeMessages[ErrorTypes.INTERNAL],
      correlationId: correlationId
    }
  };

  // In development, add detailed information
  if (isDevelopment) {
    baseResponse.error.debug = {
      originalMessage: error.message,
      stack: error.stack,
      details: error.details
    };
  }

  // For validation errors, include field-level details (safe to expose)
  if (error.type === ErrorTypes.VALIDATION && error.details) {
    baseResponse.error.validationErrors = error.details;
  }

  return baseResponse;
}

// Comprehensive error logging
function logError(error, req, correlationId) {
  const logData = {
    correlationId: correlationId,
    timestamp: new Date().toISOString(),
    error: {
      message: error.message,
      type: error.type,
      stack: error.stack,
      isOperational: error.isOperational || false
    },
    request: {
      method: req.method,
      path: req.path,
      query: req.query,
      // Never log full body - may contain passwords
      bodyKeys: Object.keys(req.body || {}),
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      userId: req.user?.id || 'anonymous'
    },
    environment: process.env.NODE_ENV
  };

  // Log at appropriate level
  if (error.isOperational) {
    logger.warn('Operational error', logData);
  } else {
    logger.error('Unexpected error', logData);
    // Alert on unexpected errors in production
    if (isProduction) {
      alertOpsTeam(logData);
    }
  }
}

// Production alerting (integrate with PagerDuty, Slack, etc.)
function alertOpsTeam(errorData) {
  // Example: Send to monitoring service
  console.error('[ALERT] Unexpected error requires attention:', errorData.correlationId);
  // In production: integrate with alerting service
  // await pagerduty.trigger(errorData);
  // await slack.postMessage('#alerts', errorData);
}

// Request correlation middleware
app.use((req, res, next) => {
  req.correlationId = req.headers['x-correlation-id'] || generateCorrelationId();
  res.setHeader('X-Correlation-ID', req.correlationId);
  next();
});

// Example route with proper error handling
app.get('/api/users/:id', async (req, res, next) => {
  try {
    const userId = parseInt(req.params.id, 10);

    if (isNaN(userId) || userId <= 0) {
      throw new AppError(
        'User ID must be a positive integer',
        ErrorTypes.VALIDATION,
        400,
        { field: 'id', received: req.params.id }
      );
    }

    // Simulated database call
    const user = await getUserById(userId);

    if (!user) {
      throw new AppError(
        `User ${userId} not found`,
        ErrorTypes.NOT_FOUND,
        404
      );
    }

    res.json({ success: true, data: user });
  } catch (error) {
    next(error);
  }
});

// Global error handler - MUST be last middleware
app.use((err, req, res, next) => {
  const correlationId = req.correlationId || generateCorrelationId();

  // Log full error details server-side
  logError(err, req, correlationId);

  // Determine status code
  const statusCode = err.statusCode || 500;

  // Send sanitized response to client
  const clientResponse = sanitizeErrorForClient(err, correlationId);

  // Security headers on error responses
  res.set({
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'Cache-Control': 'no-store'
  });

  res.status(statusCode).json(clientResponse);
});

// Catch unhandled rejections
process.on('unhandledRejection', (reason, promise) => {
  logger.error('Unhandled Rejection', { reason: reason, promise: promise });
  if (isProduction) {
    alertOpsTeam({ type: 'unhandledRejection', reason: reason });
  }
});

app.listen(3000, () => {
  logger.info(`Server started in ${process.env.NODE_ENV} mode`);
});
```

**Defense in Depth Layers**:

1. **Environment-Aware Responses**:
```javascript
// Development: Full details for debugging
{
  "error": {
    "code": "DATABASE_ERROR",
    "message": "Service temporarily unavailable",
    "correlationId": "err_1704912345_abc123",
    "debug": {
      "originalMessage": "ER_ACCESS_DENIED_ERROR",
      "stack": "Error at..."
    }
  }
}

// Production: Minimal, safe information
{
  "error": {
    "code": "DATABASE_ERROR",
    "message": "Service temporarily unavailable",
    "correlationId": "err_1704912345_abc123"
  }
}
```

2. **Error Classification**:
```javascript
// Operational errors (expected) vs Programming errors (bugs)
if (error.isOperational) {
  // Log as warning, handle gracefully
  logger.warn('Expected error', { correlationId });
} else {
  // Log as error, alert team, consider restart
  logger.error('Unexpected bug', { correlationId });
  alertOpsTeam(correlationId);
}
```

3. **Correlation ID Flow**:
```javascript
// Trace errors across services
app.use((req, res, next) => {
  req.correlationId = req.headers['x-correlation-id'] || generateCorrelationId();
  res.setHeader('X-Correlation-ID', req.correlationId);
  next();
});
// User reports: "Error ID err_1704912345_abc123"
// Ops team can search logs instantly
```

**Additional Protections**:
- **Never log sensitive data**: Filter passwords, tokens, PII from logs
- **Structured logging**: JSON format for easy parsing by log aggregators (ELK, Splunk)
- **Rate limiting on error endpoints**: Prevent error enumeration attacks
- **Security headers on error responses**: Prevent content-type sniffing
- **Graceful shutdown**: Log final state on SIGTERM for debugging
- **Health check endpoint**: Separate from error-prone business logic

No, exposing exception details to users is a serious security misconfiguration that enables attackers to gather intelligence about your system internals.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.sql.*;

public class UserServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://prod-db-01.internal:5432/userdata";
    private static final String DB_USER = "app_service";
    private static final String DB_PASS = "Pr0d_S3cr3t!2024";

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String userId = request.getParameter("id");

        try {
            Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
            PreparedStatement stmt = conn.prepareStatement(
                "SELECT * FROM users WHERE id = ?");
            stmt.setString(1, userId);
            ResultSet rs = stmt.executeQuery();
            // Process results...
        } catch (SQLException e) {
            // VULNERABLE: Exposes full exception to user
            response.setStatus(500);
            response.setContentType("text/html");
            PrintWriter out = response.getWriter();
            out.println("<h1>Database Error</h1>");
            out.println("<pre>");
            e.printStackTrace(out);  // Exposes stack trace!
            out.println("</pre>");
            out.println("<p>Connection string: " + DB_URL + "</p>");
        }
    }
}
```

**Attack Payload**:
```text
GET /users?id=invalid'char HTTP/1.1
Host: target.com
```

**Example Exposed Error Response**:
```text
Database Error

org.postgresql.util.PSQLException: ERROR: invalid input syntax for type integer: "invalid'char"
    at org.postgresql.core.v3.QueryExecutorImpl.receiveErrorResponse(QueryExecutorImpl.java:2553)
    at com.company.UserServlet.doGet(UserServlet.java:28)
    at javax.servlet.http.HttpServlet.service(HttpServlet.java:750)
    ...
Connection string: jdbc:postgresql://prod-db-01.internal:5432/userdata
```

**Why This Is Dangerous**:
- Stack traces reveal internal class names, method names, and line numbers
- Database connection strings expose internal hostnames and database names
- Exception messages reveal database type (PostgreSQL) and version information
- Attackers use this intelligence to craft targeted SQL injection or exploit known CVEs
- File paths expose OS type and application deployment structure

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.sql.*;
import java.util.UUID;
import java.util.logging.Logger;
import java.util.logging.Level;

public class UserServlet extends HttpServlet {
    private static final Logger logger = Logger.getLogger(UserServlet.class.getName());
    private DataSource dataSource;  // Injected, not hardcoded

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String userId = request.getParameter("id");
        String errorId = UUID.randomUUID().toString();

        try {
            // Input validation first
            if (userId == null || !userId.matches("^[0-9]+$")) {
                response.setStatus(400);
                response.setContentType("application/json");
                response.getWriter().write("{\"error\": \"Invalid user ID format\"}");
                return;
            }

            try (Connection conn = dataSource.getConnection();
                 PreparedStatement stmt = conn.prepareStatement(
                     "SELECT id, username, email FROM users WHERE id = ?")) {
                stmt.setInt(1, Integer.parseInt(userId));
                ResultSet rs = stmt.executeQuery();
                // Process results...
            }
        } catch (SQLException e) {
            // SECURE: Log full details internally, return generic message to user
            logger.log(Level.SEVERE, "Database error [errorId=" + errorId + "]", e);

            response.setStatus(500);
            response.setContentType("application/json");
            response.getWriter().write(
                "{\"error\": \"An internal error occurred\", " +
                "\"errorId\": \"" + errorId + "\", " +
                "\"support\": \"Contact support with this error ID\"}"
            );
        } catch (NumberFormatException e) {
            logger.log(Level.WARNING, "Invalid user ID format [errorId=" + errorId + "]", e);
            response.setStatus(400);
            response.setContentType("application/json");
            response.getWriter().write("{\"error\": \"Invalid request\"}");
        }
    }
}
```

**Key Security Controls**:
- **Error ID correlation**: Generate unique ID for each error, log it internally, return only the ID to users for support lookup
- **Generic user messages**: Never expose exception types, stack traces, or internal details
- **Internal logging**: Full exception details logged server-side with proper log levels
- **No hardcoded credentials**: Use dependency injection for database connections

For production Spring Boot applications, use a global exception handler with `@ControllerAdvice` to ensure consistent, secure error handling across all endpoints.

**PRODUCTION PATTERN**:

```java
package com.company.security;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.context.request.WebRequest;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.dao.DataAccessException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;

import javax.validation.ConstraintViolationException;
import java.time.Instant;
import java.util.UUID;

@ControllerAdvice
public class GlobalSecurityExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalSecurityExceptionHandler.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Standard error response DTO
    public record ErrorResponse(
        String errorId,
        String message,
        int status,
        Instant timestamp,
        String path
    ) {}

    @ExceptionHandler(DataAccessException.class)
    public ResponseEntity<ErrorResponse> handleDatabaseException(
            DataAccessException ex, WebRequest request) {

        String errorId = generateErrorId();
        MDC.put("errorId", errorId);

        // Log full details internally for debugging
        logger.error("Database error occurred", ex);

        // Return sanitized response to client
        ErrorResponse response = new ErrorResponse(
            errorId,
            "A database error occurred. Please try again later.",
            HttpStatus.INTERNAL_SERVER_ERROR.value(),
            Instant.now(),
            extractPath(request)
        );

        MDC.clear();
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
    }

    @ExceptionHandler(AccessDeniedException.class)
    public ResponseEntity<ErrorResponse> handleAccessDenied(
            AccessDeniedException ex, WebRequest request) {

        String errorId = generateErrorId();

        // Security events get special audit logging
        securityLogger.warn("Access denied [errorId={}, path={}, user={}]",
            errorId, extractPath(request), getCurrentUser());

        ErrorResponse response = new ErrorResponse(
            errorId,
            "Access denied",
            HttpStatus.FORBIDDEN.value(),
            Instant.now(),
            extractPath(request)
        );

        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(response);
    }

    @ExceptionHandler(ConstraintViolationException.class)
    public ResponseEntity<ErrorResponse> handleValidation(
            ConstraintViolationException ex, WebRequest request) {

        String errorId = generateErrorId();
        logger.info("Validation failed [errorId={}]", errorId);

        // Safe: validation messages are controlled by annotations
        ErrorResponse response = new ErrorResponse(
            errorId,
            "Invalid request parameters",
            HttpStatus.BAD_REQUEST.value(),
            Instant.now(),
            extractPath(request)
        );

        return ResponseEntity.badRequest().body(response);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleAllUnexpected(
            Exception ex, WebRequest request) {

        String errorId = generateErrorId();
        MDC.put("errorId", errorId);

        // Log full stack trace for unexpected exceptions
        logger.error("Unexpected error occurred", ex);

        // NEVER expose exception class names or messages
        ErrorResponse response = new ErrorResponse(
            errorId,
            "An unexpected error occurred. Please contact support.",
            HttpStatus.INTERNAL_SERVER_ERROR.value(),
            Instant.now(),
            extractPath(request)
        );

        MDC.clear();
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
    }

    private String generateErrorId() {
        return UUID.randomUUID().toString().substring(0, 8).toUpperCase();
    }

    private String extractPath(WebRequest request) {
        return request.getDescription(false).replace("uri=", "");
    }

    private String getCurrentUser() {
        // Extract from SecurityContext
        return "anonymous";  // Simplified
    }
}
```

**Spring Boot application.properties Configuration**:

```properties
# CRITICAL: Disable default error details in production
server.error.include-message=never
server.error.include-binding-errors=never
server.error.include-stacktrace=never
server.error.include-exception=false

# Disable Whitelabel error page (reveals Spring Boot version)
server.error.whitelabel.enabled=false

# Production logging - no DEBUG in prod
logging.level.root=WARN
logging.level.com.company=INFO
logging.level.SECURITY_AUDIT=INFO

# Structured logging for SIEM integration
logging.pattern.console=%d{ISO8601} [%X{errorId}] %-5level %logger{36} - %msg%n
```

**Defense in Depth Layers**:

1. **Application Layer** - Global exception handler catches all exceptions:
```java
@ExceptionHandler(Exception.class)
public ResponseEntity<ErrorResponse> handleAll(Exception ex) {
    // Sanitize before returning
}
```

2. **Framework Layer** - Spring Boot properties disable verbose errors:
```properties
server.error.include-stacktrace=never
```

3. **Infrastructure Layer** - Reverse proxy strips any leaked details:
```nginx
# nginx.conf
proxy_intercept_errors on;
error_page 500 502 503 504 /custom_50x.html;

# Remove server version headers
server_tokens off;
proxy_hide_header X-Powered-By;
```

**Additional Protections**:
- **MDC (Mapped Diagnostic Context)**: Correlate logs across distributed systems using the same errorId
- **Separate security audit log**: Security events logged to dedicated stream for SIEM ingestion
- **Environment-specific profiles**: Use Spring profiles to ensure DEBUG logging never enabled in production
- **Custom error pages**: Replace default error pages that might reveal framework versions
- **Response header sanitization**: Remove X-Powered-By, Server headers that reveal technology stack

**Testing Your Error Handling**:
