API error handling requires special attention because JSON responses can leak just as much information as HTML error pages, and they're often parsed programmatically by attackers.

**PRODUCTION PATTERN**:

```php
<?php
// ErrorHandler.php - Production-grade API error handling

namespace App\Http;

use Throwable;
use Psr\Log\LoggerInterface;

class SecureApiErrorHandler
{
    private LoggerInterface $logger;
    private string $environment;
    private array $sensitivePatterns = [
        '/password/i',
        '/secret/i',
        '/api[_-]?key/i',
        '/token/i',
        '/credential/i',
        '/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/',
        '/\b(?:\d{4}[- ]?){3}\d{4}\b/', // Credit card pattern
    ];

    public function __construct(LoggerInterface $logger)
    {
        $this->logger = $logger;
        $this->environment = getenv('APP_ENV') ?: 'production';
    }

    public function handle(Throwable $exception): array
    {
        $errorId = $this->generateErrorId();
        $statusCode = $this->determineStatusCode($exception);

        // Log full details securely
        $this->logException($exception, $errorId, $statusCode);

        // Return sanitized response
        return $this->buildResponse($exception, $errorId, $statusCode);
    }

    private function generateErrorId(): string
    {
        return sprintf(
            '%s-%s',
            date('Ymd'),
            bin2hex(random_bytes(8))
        );
    }

    private function determineStatusCode(Throwable $exception): int
    {
        // Map exception types to HTTP status codes
        $mapping = [
            'InvalidArgumentException' => 400,
            'AuthenticationException' => 401,
            'AuthorizationException' => 403,
            'NotFoundException' => 404,
            'ValidationException' => 422,
            'RateLimitException' => 429,
            'PDOException' => 500,
            'RuntimeException' => 500,
        ];

        $class = get_class($exception);
        foreach ($mapping as $type => $code) {
            if (str_contains($class, $type)) {
                return $code;
            }
        }

        return 500;
    }

    private function logException(
        Throwable $exception,
        string $errorId,
        int $statusCode
    ): void {
        $context = [
            'error_id' => $errorId,
            'status_code' => $statusCode,
            'exception_class' => get_class($exception),
            'file' => $exception->getFile(),
            'line' => $exception->getLine(),
            'trace' => $exception->getTraceAsString(),
            'request_uri' => $_SERVER['REQUEST_URI'] ?? 'CLI',
            'request_method' => $_SERVER['REQUEST_METHOD'] ?? 'CLI',
            'client_ip' => $this->getClientIp(),
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'Unknown',
        ];

        // Sanitize message before logging (remove potential secrets)
        $sanitizedMessage = $this->sanitizeMessage($exception->getMessage());

        $this->logger->error($sanitizedMessage, $context);
    }

    private function sanitizeMessage(string $message): string
    {
        // Remove potential sensitive data from logs too
        foreach ($this->sensitivePatterns as $pattern) {
            $message = preg_replace($pattern, '[REDACTED]', $message);
        }
        return $message;
    }

    private function buildResponse(
        Throwable $exception,
        string $errorId,
        int $statusCode
    ): array {
        // Production: Generic messages only
        if ($this->environment === 'production') {
            return [
                'success' => false,
                'error' => [
                    'code' => $this->getPublicErrorCode($statusCode),
                    'message' => $this->getPublicMessage($statusCode),
                    'reference' => $errorId,
                ],
            ];
        }

        // Development: Include details (but still sanitized)
        return [
            'success' => false,
            'error' => [
                'code' => $this->getPublicErrorCode($statusCode),
                'message' => $this->sanitizeMessage($exception->getMessage()),
                'reference' => $errorId,
                'debug' => [
                    'exception' => get_class($exception),
                    'file' => basename($exception->getFile()),
                    'line' => $exception->getLine(),
                ],
            ],
        ];
    }

    private function getPublicErrorCode(int $statusCode): string
    {
        $codes = [
            400 => 'INVALID_REQUEST',
            401 => 'AUTHENTICATION_REQUIRED',
            403 => 'ACCESS_DENIED',
            404 => 'RESOURCE_NOT_FOUND',
            422 => 'VALIDATION_ERROR',
            429 => 'RATE_LIMIT_EXCEEDED',
            500 => 'INTERNAL_ERROR',
            503 => 'SERVICE_UNAVAILABLE',
        ];

        return $codes[$statusCode] ?? 'UNKNOWN_ERROR';
    }

    private function getPublicMessage(int $statusCode): string
    {
        $messages = [
            400 => 'The request was invalid or malformed.',
            401 => 'Authentication is required to access this resource.',
            403 => 'You do not have permission to access this resource.',
            404 => 'The requested resource was not found.',
            422 => 'The request data failed validation.',
            429 => 'Too many requests. Please try again later.',
            500 => 'An unexpected error occurred. Please try again.',
            503 => 'Service temporarily unavailable. Please try again later.',
        ];

        return $messages[$statusCode] ?? 'An error occurred processing your request.';
    }

    private function getClientIp(): string
    {
        // Handle proxies securely
        $headers = [
            'HTTP_CF_CONNECTING_IP', // Cloudflare
            'HTTP_X_FORWARDED_FOR',
            'REMOTE_ADDR',
        ];

        foreach ($headers as $header) {
            if (!empty($_SERVER[$header])) {
                $ips = explode(',', $_SERVER[$header]);
                return trim($ips[0]);
            }
        }

        return 'Unknown';
    }
}

// Usage in API controller
class ApiController
{
    private SecureApiErrorHandler $errorHandler;

    public function handleRequest(): void
    {
        header('Content-Type: application/json; charset=utf-8');

        // Security headers
        header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
        header('Cache-Control: no-store, no-cache, must-revalidate');

        try {
            $result = $this->processRequest();
            http_response_code(200);
            echo json_encode(['success' => true, 'data' => $result]);

        } catch (Throwable $e) {
            $response = $this->errorHandler->handle($e);
            http_response_code($this->getStatusFromResponse($response));
            echo json_encode($response, JSON_UNESCAPED_SLASHES);
        }
    }
}
```

